library(shiny)
library(later)

roll_core <- function(n, d){
  sample.int(d, n, replace = TRUE)
}

roll_adv <- function(d,str="a"){
  p <- nchar(str)
  max(sample.int(d, p+1, replace = TRUE))
}

roll_dis <- function(d,str="d"){
  p <- nchar(str)
  min(sample.int(d, p+1, replace = TRUE))
}

transform_dice <- function(expr){
  expr <- gsub("\\s+", "", tolower(expr))
  # advantage
  expr <- gsub("([0-9]*)d([0-9]+)(a+)",
               "roll_adv(\\2,\"\\3\")",
               expr)
  # disadvantage
  expr <- gsub("([0-9]*)d([0-9]+)(d+)",
               "roll_dis(\\2,\"\\3\")",
               expr)
  # standard dice
  expr <- gsub("([0-9]*)d([0-9]+)",
               "sum(roll_core(ifelse('\\1'=='',1,as.numeric('\\1')),\\2))",
               expr)
  expr
}

roll_expr <- function(expr){
  code <- transform_dice(expr)
  eval(parse(text = code))
}

roll_dice <- function(expr){
  print(expr)
  res=roll_expr(expr)
  print(res)
  list(
    rolls = expr,
    total = res
  )
}


dice_icon <- function(sides){
  shape <- if(sides %in% c(4,6,8,10,12,20)) {
    paste0("d",sides)
  } else {
    "d6"
  }
  div(
    class = paste("die",shape)
  )
}

guessSides<-function(x){
  if(grepl("d4",x)) return(4)
  if(grepl("d6",x)) return(6)
  if(grepl("d8",x)) return(8)
  if(grepl("d10",x)) return(10)
  if(grepl("d12",x)) return(12)
  if(grepl("d20",x)) return(20)
  if(grepl("d100",x)) return(100)
  return(6)
}

labeldice<-function(string) {
    res=strsplit(string,":")[[1]]
    sides=guessSides(string)
    icon=dice_icon(sides)
    if(length(res)==1) {
      return(list(label=string,sides=sides,icon=icon,expr=string))
    } else {
      return(list(label=res[1],sides=sides,icon=icon,expr=res[2]))
    }
}

