ui <- fluidPage(
  ## Tags
  tags$head(
    tags$style(HTML("
      body {
        background-image: url('./background.jpg');
        background-size: cover;
        color: white;
        background-attachment: fixed;
      }
      .main-container {
      background: transparent !important;
      }
    ")),
    tags$head(
      tags$link(
        rel = "stylesheet",
        type = "text/css",
        href = "dice.css"
      )
    )
  ),
  ## UI
  titlePanel("Dice Roller"),
  fluidRow(
    h4("Dice Tray"),
    uiOutput("dice_tray",class="dice_tray"),
    column(4,
      textInput("newdice","Add dice (e.g. 3d6+1)"),
      actionButton("add","Add Dice"),
      h4("Remove dice:",class="remove_header"),
      uiOutput("dice_buttons")
    ),
    column(8,
             h3("Rolling Die"),
            uiOutput("die_rolled"),
             div(
               id = "roll_display",
               class="roll_display",
               uiOutput("rolling_die")
             ),
      h3("Roll Log"),
      tableOutput("log"),
      downloadButton("download_log","Download log")
    )
  )
)

server <- function(input, output, session){
  ## DEFINE OBJECTS
  ## Reactive values to store dice 
  dice <- reactiveValues(list = list())
  dice$list <- list(
    "dice_1" = labeldice("d4"),
    "dice_2" = labeldice("d6"),
    "dice_3" = labeldice("d20")
  )
  ## Reactive value to store log of rolls
  log <- reactiveVal(data.frame(
    time = character(),
    dice = character(),
    result = numeric()
  ))

  ## DEFINE UI OUTPUTS
  ## UI for dice tray and buttons 
  output$dice_tray <- renderUI({
    if(length(dice$list) == 0) return(NULL)
    div(
      class = "dice_button",
      tagList(
      lapply(names(dice$list), function(id){
        die <- dice$list[[id]]
        print(die)
        actionButton(
          id,
          label = div(die$icon,die$label), 
          class = "dice_button"
        )
      })
      )
    )
  })

  output$rolling_die <- renderUI({
    div(class=paste("big_die", "d4"), "?")
  })

  output$die_rolled <- renderUI({
    h3("(Roll any die)")
  })

  ## For removing dice
  output$dice_buttons <- renderUI({
    lapply(names(dice$list), function(id){
      label <- dice$list[[id]]$label
      div(
      class = "remove_button",
      fluidRow(
        column(
          8,
          h4(label)
        ),
        column(
          4,
          actionButton(paste0("remove_",id),"X",class = "remove_button")
        )
      )
      )
    })
  })

  ## OBSERVERS
  ## Observer for the add dice button
  observeEvent(input$add,{
    id <- paste0("dice_", length(dice$list)+1)
    dicedetails <- labeldice(input$newdice)
    dice$list[[id]] <- list(id=id,
                            label=dicedetails$label,
                            sides=dicedetails$sides,
                            icon=dicedetails$icon,
                            expr=dicedetails$expr)
  })

  ## Set up observers for rolling dice
  observe({
    lapply(names(dice$list), function(id){
      ## Observer for rolling dice - updates the display and log
      observeEvent(input[[id]],{
        res <- roll_dice(dice$list[[id]]$expr)
        sides <- dice$list[[id]]$sides
        output$die_rolled <- renderUI({
          h3(dice$list[[id]]$label)
        })
        output$rolling_die <- renderUI({
          div(
            class=paste("big_die",paste0("d",sides),"rolling"),
            "?"
          )
        })
        # reveal result after animation delay
        later(function(){
          output$rolling_die <- renderUI({
            div(class=paste("big_die", paste0("d",sides)), res$total)
          })
        }, delay = 0.7)
        new <- data.frame(
          time = as.character(Sys.time()),
          dice = dice$list[[id]]$label,
          expr = dice$list[[id]]$expr,
          result = res$total
        )
        log(rbind(new,log()))
      }, ignoreInit = TRUE)
    })
  })

  ## Set up observers for removing dice
  observe({
    lapply(names(dice$list), function(id){
      observeEvent(input[[paste0("remove_",id)]],{
        dice$list[[id]] <- NULL
      }, ignoreInit = TRUE)
    })
  })

  ## Output log
  output$log <- renderTable(log())

  output$download_log <- downloadHandler(
    filename = function(){"dice_log.csv"},
    content = function(file){
      write.csv(log(),file,row.names=FALSE)
    }
  )
}

shinyApp(ui, server)

body {
    background-image: url("background.jpg");
    background-size: cover;
    background-attachment: fixed;
}

/* main tray */
.dice_tray {
    background: rgba(40,40,40,0.9);
    border-radius: 18px;
    padding: 20px;
    margin-top: 20px;

    box-shadow:
	inset 0 0 20px rgba(0,0,0,0.8),
	0 6px 20px rgba(0,0,0,0.6);

    border: 2px solid #444;
}

/* dice buttons */
.dice_button button {
    font-size: 18px;
    font-weight: bold;

    margin: 6px;
    padding: 12px 18px;

    border-radius: 12px;

    background: linear-gradient(#fafafa,#cfcfcf);

    border: 2px solid #888;

    box-shadow:
	0 3px 0 #777,
	0 4px 8px rgba(0,0,0,0.4);
}

/* pressed effect */
.dice_button button:active {
    transform: translateY(3px);
    box-shadow: 0 1px 0 #777;
}


.remove_header {
    background:#222;
    font-size:18px;
    padding:6px;
    margin:4px 0;
    border-radius:6px;
    color:grey;
}

.remove_button {
    background:#222;
    font-size:6px;
    padding:6px;
    margin:4px 0;
    border-radius:6px;
    color:grey;
}

/* roll log */
.roll-log {
    background: rgba(0,0,0,0.7);
    color: #8cff8c;

    padding: 10px;
    border-radius: 10px;

    font-family: monospace;
}

#roll_display {
  text-align:center;
  margin:40px;
}

#rolling_die {
  width:80px;
  height:80px;
  font-size:28px;
  margin:auto;
}

@keyframes dice-roll {

  0%   { transform: rotate(0deg) scale(1); }
  25%  { transform: rotate(90deg) scale(1.2); }
  50%  { transform: rotate(180deg) scale(0.9); }
  75%  { transform: rotate(270deg) scale(1.2); }
  100% { transform: rotate(360deg) scale(1); }

}

.rolling {
  animation: dice-roll 0.6s ease;
}

.die {
  display:inline-flex;
  align-items:center;
  justify-content:center;
  width:32px;
  height:32px;
  margin-right:6px;
  font-size:12px;
  font-weight:bold;
  color:white;
  background:#444;
  border:2px solid #222;
  box-shadow: 0 2px 3px rgba(0,0,0,0.4);
}

.big_die {
  display:inline-flex;
  align-items:center;
  justify-content:center;
  width:120px;
  height:120px;
  margin-right:10px;
  font-size:30px;
  font-weight:bold;
  color:white;
  outline-color: #8cff8c;
  background:#444;
  border:4px solid #222;
  box-shadow: 0 3px 5px rgba(0,0,0,0.4);
}

/* shapes */

.d4  { clip-path: polygon(50% 0%, 0% 100%, 100% 100%); }
.d6  { border-radius:4px; }
.d8  { clip-path: polygon(50% 0%, 100% 50%, 50% 100%, 0% 50%); }
.d10 { clip-path: polygon(50% 0%, 85% 20%, 100% 60%, 70% 100%, 30% 100%, 0% 60%, 15% 20%); }
.d12 { clip-path: polygon(50% 0%, 80% 20%, 100% 50%, 80% 80%, 50% 100%, 20% 80%, 0% 50%, 20% 20%); }
.d20 { clip-path: polygon(50% 0%, 80% 15%, 100% 45%, 90% 80%, 50% 100%, 10% 80%, 0% 45%, 20% 15%); }

/* hover animation for tray feel */

.die:hover {
  transform: scale(1.15) rotate(6deg);
}
